from flask import Flask, redirect, request, url_for
import requests

app = Flask(__name__)

# Configuration
CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
AUTHORIZATION_ENDPOINT = 'https://your_auth_server/auth'
TOKEN_ENDPOINT = 'https://your_auth_server/token'
REDIRECT_URI = 'http://localhost:5000/callback'

@app.route('/')
def index():
    auth_url = f"{AUTHORIZATION_ENDPOINT}?response_type=id_token&client_id={CLIENT_ID}&redirect_uri={REDIRECT_URI}&scope=openid"
    return redirect(auth_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    token_response = requests.post(
        TOKEN_ENDPOINT,
        data={
            'grant_type': 'authorization_code',
            'client_id': CLIENT_ID,
            'client_secret': CLIENT_SECRET,
            'redirect_uri': REDIRECT_URI,
            'code': code
        }
    )
    token_data = token_response.json()
    id_token = token_data.get('id_token')
    # Process the id_token as needed
    return f'ID Token: {id_token}'

if __name__ == '__main__':
    app.run(debug=True)